var e=[{id:`L2_1`,type:`dialog`,speaker:`MINHA_G1_NUL.L_NULL`,text:{KOREA:`언젠간 관리자 양반도 내 덕에 목숨을 건지는 날이 올 거야. 대사님은 내가 수많은 인명을 구할 팔자랬거든. 그러니 날 미리미리 은인으로 모셔두라고.`,JPN:`いつか管理者も私のおかげで命が助かる日が来るよ。大師は私がたくさんの人の命を救う運命だと言ってた。だから私のことはあらかじめ恩人と思って敬っておくのね。`,ENG:`One day, you'll owe your life to me. My master said I'm destined to save countless lives. So you'd better start treatin' me like your life-saver.`,TWN:`總有一天，管理者也會因為我撿回一條命的。大師說過，我是會拯救無數性命的命格。所以趁早把我當恩人伺候吧。`},stage:{bg:`LIFETIME`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MINHA_G1_NUL.L_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`MINHA_G1_NUL.L_NULL`,text:{KOREA:`그래 그래- 그렇게 감사한 마음을 담아서…`,JPN:`そうそう、感謝の気持ちを込めて……`,ENG:`Yeah, that's it... Show some proper gratit–`,TWN:`對、對—懷著感激的心……`},stage:{bg:`LIFETIME`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MINHA_G1_NUL.L_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`MINHA_G1_NUL.L_NULL`,text:{KOREA:`잠깐 누가 머리 쓰다듬으랬어? 큰절이나 올리라고! 바보!`,JPN:`ちょっと、頭を撫でろとは言ってないでしょ！　お辞儀しなさいよ！　バカ！`,ENG:`Hey! Who told you to pat my head?! Bow all the way down! Idiot!`,TWN:`等一下，誰准你摸我頭的？叫你行大禮啦！笨蛋！`},stage:{bg:`LIFETIME`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MINHA_G1_NUL.L_NULL`,face:`UNIT_SURPRISE`},R:null}}}];export{e as default};